Here's a well-structured MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(HttpMessageHandler handler)
        => new(new HttpClient(handler));

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello world"),
        });
        var fetcher = CreateFetcher(handler);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.NotFound,
        });
        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        var fetcher = CreateFetcher(handler);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_SlowResponse_CancelledByTimeout()
    {
        // Arrange — handler that delays longer than the [Timeout]
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        var fetcher = CreateFetcher(handler);

        // Act & Assert — TestContext.CancellationToken fires when [Timeout] expires
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    /// <summary>Minimal handler that returns a canned response or simulates delay.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage? response = null,
                           TimeSpan delay = default)
        {
            _response = response ?? new HttpResponseMessage(HttpStatusCode.OK);
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            return _response;
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(N)]` + pass `_testContext.CancellationToken` into async calls |
| **Explicit cancellation** | Create a `CancellationTokenSource`, cancel it, assert `TaskCanceledException` |
| **Timeout-driven cancel** | Slow handler + short `[Timeout]` — the framework cancels via `TestContext.CancellationToken` |
| **Error status codes** | `Assert.ThrowsExactlyAsync` instead of `[ExpectedException]` |
| **No mocking library needed** | Lightweight `FakeHandler` extending `HttpMessageHandler` |

The critical detail: always flow `TestContext.CancellationToken` into your async calls so `[Timeout]` can actually cancel the test instead of letting it hang.
